import React from "react";

import styles from "./PixelTooltip.module.css";

export interface PixelTooltipProps {
  content: string;
  children: React.ReactNode;
  position?: "top" | "bottom" | "left" | "right";
  delay?: number;
}

export function PixelTooltip({
  content,
  children,
  position = "top",
  delay = 200,
}: PixelTooltipProps) {
  const [isVisible, setIsVisible] = React.useState(false);
  const [coords, setCoords] = React.useState({ x: 0, y: 0, width: 0 });
  const timeoutRef = React.useRef<ReturnType<typeof setTimeout> | null>(null);
  const triggerRef = React.useRef<HTMLDivElement>(null);

  const handleMouseEnter = React.useCallback(() => {
    timeoutRef.current = setTimeout(() => {
      if (triggerRef.current) {
        const rect = triggerRef.current.getBoundingClientRect();
        setCoords({
          x: rect.left,
          y: rect.bottom,
          width: rect.width,
        });
      }
      setIsVisible(true);
    }, delay);
  }, [delay]);

  const handleMouseLeave = React.useCallback(() => {
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
      timeoutRef.current = null;
    }
    setIsVisible(false);
  }, []);

  React.useEffect(
    () => () => {
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
      }
    },
    [],
  );

  return (
    <>
      <div
        ref={triggerRef}
        className={styles.trigger}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
      >
        {children}
      </div>

      {isVisible ? (
        <div
          className={`${styles.tooltip} ${styles[position]} ${styles.show}`.trim()}
          style={{
            left: `${coords.x + 5}px`,
            top: `${coords.y + 8}px`,
            width: `${Math.max(coords.width - 20, 60)}px`,
          }}
        >
          <div className={styles.pixelContainer}>
            <div className={styles.content}>{content}</div>
          </div>
        </div>
      ) : null}
    </>
  );
}

export default PixelTooltip;

.trigger {
  display: inline-flex;
  align-items: center;
  cursor: help;
}

.tooltip {
  position: fixed;
  z-index: var(--z-tooltip);
  pointer-events: none;
  opacity: 0;
  transition:
    opacity 250ms ease-in-out,
    transform 250ms ease-in-out;
}

.tooltip.show {
  opacity: 1;
  animation: tooltipFadeIn 250ms ease-out forwards;
}

.pixelContainer {
  position: relative;
  width: fit-content;
  max-width: 150px;
  padding: 6px 10px;
  background: var(--accent-primary);
  border: 1px solid var(--accent-primary);
  white-space: normal;
  image-rendering: pixelated;
  image-rendering: -moz-crisp-edges;
  image-rendering: crisp-edges;
}

.content {
  position: relative;
  z-index: 1;
  color: #fff;
  font-family: var(--font-mono);
  font-size: 11px;
  line-height: 1.3;
  text-align: left;
}

.tooltip.top {
  margin-top: -8px;
  transform: translateY(-100%);
}

.tooltip.bottom {
  margin-top: 0;
  transform: translateY(0);
}

.tooltip.left {
  margin-left: -8px;
  transform: translateX(-100%) translateY(-50%);
}

.tooltip.right {
  margin-left: 8px;
  transform: translateY(-50%);
}

@keyframes tooltipFadeIn {
  0% {
    opacity: 0;
    transform: translateY(-4px) scale(0.95);
  }

  100% {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

@media (max-width: 768px) {
  .tooltip {
    display: none;
  }
}
